import React from 'react';
import { Route, Switch } from 'react-router-dom';
import { NavLink } from 'react-router-dom';
import home from '../components/home';
import experience from '../components/experience';
import skills from '../components/skills';
import contact from '../components/contact';
import style from '../components/css/style.module.css';
import box from '../components/css/box.module.css';
import myImage from '../components/assets/img/prof-pic.png'

function Box() {
    return (
      <div className={box.wrapper}>
        <div className={box.head_wrap}>
          <div className={box.r_col}>
            <ul className={box.ul_wrap}>
              <li className={box.ul_li}><span className={box.r_txt_num}>2</span><br /><span className={box.r_txt_desc}>Projects</span></li>
              <li className={box.ul_li}><span className={box.r_txt_num}>4</span><br /><span className={box.r_txt_desc}>Languages</span></li>
              <li className={box.ul_li}><span className={box.r_txt_num}>18</span><br /><span className={box.r_txt_desc}>Coffee</span></li>
            </ul>
          </div>
          <div className={box.img_wrapper}>
            <div className={box.img_clip}>
              <img src={myImage} alt="my profile" />
            </div>
          </div>
          <div className={box.l_col}>
            <ul className={box.ul_wrap}>
              <li><a href="https://linkedin.com/in/m-yoshi44"  className={[box.l_li, style.bg_purple, style.btn_min].join(' ')} target="_blank">Connect</a></li>
              <li><NavLink className={[box.l_li, style.bg_blue, style.btn_min].join(' ')} to="/skills" activeClassName="">Projects</NavLink></li>
            </ul>
          </div>
        </div>
        <Switch>
          <Route path="/experience" component={experience} />
          <Route path="/skills" component={skills} />
          <Route path="/contact" component={contact} />
          <Route path="/" component={home} />
        </Switch>
      </div>
    );
  }

  export default Box;