import React from 'react';
import style from '../components/css/style.module.css';
import footer from '../components/css/footer.module.css';
import twitterImg from '../components/assets/img/twitter.svg';
import gitImg from '../components/assets/img/github.svg';
import linkedImg from '../components/assets/img/linkedin.svg';

function Footer() {
    return (
      <footer className={footer.wrapper}>
        <div className={footer.content_wrapper}>
          <div className={footer.content}>
            <div className={footer.f_text_wrap}>
              <h2 className={[footer.f_text, style.txt_purple].join(' ')}>Thank you for visiting my profile!</h2>
              <h3 className={footer.f_text}>Let's keep in touch.</h3>
            </div>
            <ul className={footer.r_menu_wrap}>
              <li><a href="https://github.com/yoshimariko" target="_blank"><img src={gitImg} alt="github" /></a></li>
              <li><a href="https://twitter.com/Mariko_YY" target="_blank"><img src={twitterImg} alt="twitter" /></a></li>
              <li><a href="https://linkedin.com/in/m-yoshi44" target="_blank"><img src={linkedImg} alt="linkedin" /></a></li>
            </ul>
          </div>
          <hr className={[footer.f_hr, style.bg_grey].join(' ')} />
          <div className={footer.copyright}>
            <div className={footer.c_text_wrap}>
              <p><i className="far fa-copyright"></i> 2020 Yoshimoto Mariko</p>
            </div>
            <ul className={footer.c_menu_wrap}>
              <li>Made with <span className={style.txt_06}><i className="fas fa-heart"></i></span></li>
            </ul>
            <ul className={[footer.c_menu_wrap, footer.tablet_menu, footer.for_tablet].join(' ')}>
              <li><a href="https://github.com/yoshimariko" target="_blank" className={style.txt_grey}>GitHub</a></li>
              <li><a href="https://twitter.com/Mariko_YY" target="_blank" className={style.txt_grey}>Twitter</a></li>
              <li><a href="https://linkedin.com/in/m-yoshi44" target="_blank" className={style.txt_grey}>LinkedIn</a></li>
            </ul>
          </div>
        </div>
      </footer>
    );
  }

  export default Footer;