import React from 'react';
import style from '../components/css/style.module.css';
import experience from '../components/css/experience.module.css';


function Experience() {
    return (
      <div className={experience.wrapper}>
        <h2 className={style.title}>Experience</h2>
        <hr className={[style.box_hr, style.bg_grey].join(' ')} />
        <div className={experience.content}>
          <div className={[experience.card_row, experience.l_card].join(' ')}>
            <div className={[experience.card, experience.l_card, style.bg_dkgrey].join(' ')}>
              <span className={experience.card_sub}>2011</span>
              <h4 className={[style.txt_purple, style.mr_b5].join(' ')}>Centro Escolar University</h4>
              <p className={[style.txt_08, style.txt_grey].join(' ')}>BSBA Major in Marketing Management</p>
            </div>
          </div>
          <div className={[experience.card_row, experience.r_card].join(' ')}>
            <div className={[experience.card, experience.r_card, style.bg_dkgrey].join(' ')}>
              <span className={experience.card_sub}>2015.Mar - 2015.Apr</span>
              <h4 className={[style.txt_purple, style.mr_b5].join(' ')}>Be-i co. ltd.,</h4>
              <p className={[style.txt_08, style.txt_grey].join(' ')}>Part-time Web Developer</p>
              <hr className={[experience.hr, style.bg_grey].join(' ')} />
              <p className={style.txt_08}>- with zero knowledge in programming, I started creating simple webpages and updating our company clients' websites with basic HTML, CSS and Jquery.</p>
            </div>
          </div>
          <div className={[experience.card_row, experience.l_card].join(' ')}>
            <div className={[experience.card, experience.l_card, style.bg_dkgrey].join(' ')}>
              <span className={experience.card_sub}>2015.May - 2017.Mar</span>
              <h4 className={[style.txt_purple, style.mr_b5].join(' ')}>Be-i co. ltd.,</h4>
              <p className={[style.txt_08, style.txt_grey].join(' ')}>In-house Web Developer</p>
              <hr className={[experience.hr, style.bg_grey].join(' ')} />
              <p className={style.txt_08}>- Started working on new projects directly with clients from product planning to development. Conceptualizing new market-worthy applications and services depending on the current demands and trends while maintaining and enhancing prior software. **Mainly using Wordpress</p>
            </div>
          </div>
          <div className={[experience.card_row, experience.r_card].join(' ')}>
            <div className={[experience.card, experience.r_card, style.bg_dkgrey].join(' ')}>
              <span className={experience.card_sub}>2017.Apr - 2019.Sep</span>
              <h4 className={[style.txt_purple, style.mr_b5].join(' ')}>Be-i co. ltd.,</h4>
              <p className={[style.txt_08, style.txt_grey].join(' ')}>Job Assignment (Webmaster) - Major Automaker Company</p>
              <hr className={[experience.hr, style.bg_grey].join(' ')} />
              <p className={style.txt_08}>- Manages the organization’s websites including the corporate site, newsroom and others. Periodic checking of contents to ensure accuracy and relevancy while working closely with stakeholders and other cross-functional teams globally.</p>
            </div>
          </div>
          <div className={[experience.card_row, experience.l_card].join(' ')}>
            <div className={[experience.card, experience.l_card, style.bg_dkgrey].join(' ')}>
              <span className={experience.card_sub}>2019.Oct - Present</span>
              <h4 className={[style.txt_purple, style.mr_b5].join(' ')}>Be-i co. ltd.,</h4>
              <p className={[style.txt_08, style.txt_grey].join(' ')}>In-house Web Developer</p>
              <hr className={[experience.hr, style.bg_grey].join(' ')} />
              <p className={style.txt_08}>- Back to the main office as one of the main developers.</p>
            </div>
        </div>
      </div>
    </div>
    );
  }

  export default Experience;