import React, {useEffect} from 'react';
import { NavLink } from 'react-router-dom';
import header from '../components/css/header.module.css';

function Header() {
  useEffect(() => {
    var scriptSRC = document.createElement('script');
    scriptSRC.type = 'text/javascript';
    scriptSRC.src = 'assets/js/particles.min.js';

    var scriptINI = document.createElement('script');
    scriptINI.type = 'text/javascript';
    scriptINI.src = 'assets/js/script.js';
    document.getElementById('particles-js').appendChild(scriptSRC);
    document.getElementById('particles-js').appendChild(scriptINI);
  });
  return (
    <header className={header.wrapper}>
      <div className={header.content_wrapper}>
        <div className={header.content}>
          <ul className={header.menu_wrap}>
            <li><NavLink className={header.navLink} to="/" activeClassName="">Home</NavLink></li>
            <li><NavLink className={header.navLink} exact to="/skills" activeClassName="">Skills</NavLink></li>
            <li><NavLink className={header.navLink} exact to="/experience" activeClassName="">Experience</NavLink></li>
          </ul>
          <ul className={header.r_menu_wrap}>
            <li><a href="https://github.com/yoshimariko" target="_blank"><i className="fab fa-github"></i></a></li>
            <li><a href="https://twitter.com/Mariko_YY" target="_blank"><i className="fab fa-twitter"></i></a></li>
            <li><a href="https://linkedin.com/in/m-yoshi44" target="_blank"><i className="fab fa-linkedin-in"></i></a></li>
          </ul>
        </div>
      </div>
      <div id="particles_wrap">
        <div id="particles-js"></div>
      </div>
    </header>
  );
}

  export default Header;