import React from 'react';
import skills from '../components/css/skills.module.css';
import style from '../components/css/style.module.css';
import discord from '../components/assets/img/skills/img_discord.png';
import profile from '../components/assets/img/skills/img_profile.png';

function Skill() {
    return (
      <div className={skills.wrapper}>
        <div className={skills.row_wrap}>
          <h2 className={style.title}>Skills</h2>
          <hr className={[style.box_hr, style.bg_grey].join(' ')} />
          <div className={skills.content}>
            <p>HTML5</p>
            <div className={[skills.bar, style.bg_grey, skills.expert].join(' ')}></div>
            <p>CSS3</p>
            <div className={[skills.bar, style.bg_grey, skills.expert].join(' ')}></div>
            <p>JavaScript</p>
            <div className={[skills.bar, style.bg_grey, skills.advanced].join(' ')}></div>
            <p>PHP</p>
            <div className={[skills.bar, style.bg_grey, skills.intermediate].join(' ')}></div>
            <p>ReactJS, NodeJS</p>
            <div className={[skills.bar, style.bg_grey, skills.basic].join(' ')}></div>
          </div>
        </div>
        <div className={skills.row_wrap}>
          <h2 className={style.title}>Portfolio</h2>
          <hr className={[style.box_hr, style.bg_grey].join(' ')} />
          <div className={skills.port_wrap}>
            <div className={skills.port_box}>
              <div className={skills.port_img}><img src={discord} /></div>
              <dl className={skills.port_txt}>
                <dt className={skills.port_title}><a href="https://github.com/yoshimariko/MoominBot" className={style.link}>Moomin Bot</a></dt>
                <dt className={skills.port_desc}>( Discord.js, Node.js, API )</dt>
              </dl>
            </div>
            <div className={skills.port_box}>
              <div className={skills.port_img}><img src={profile} /></div>
              <dl className={skills.port_txt}>
                <dt className={skills.port_title}>Online Portfolio</dt>
                <dt className={skills.port_desc}>( React.js )</dt>
              </dl>
            </div>
          </div>
        </div>
      </div>
    );
  }

  export default Skill;