import React from 'react';
import ReactDOM from 'react-dom';
import Header from './components/header';
import Footer from './components/footer';
import Box from './components/box';
import './index.css';
import { BrowserRouter } from 'react-router-dom';
import { NavLink } from 'react-router-dom';

function Main() {
    return (
      <div className="wrapper">
            <BrowserRouter>
              <div className="header-wrap">
              <div className="hamburger_wrapper" id="hamburger-menu">
                <div className="hamburger">
                    <input type="checkbox" />
                    <span></span>
                    <span></span>
                    <span></span>
                  <ul className="hamburger_menu">
                    <li><NavLink className="navLink" to="/" activeClassName="">Home</NavLink></li>
                    <li><NavLink className="navLink" exact to="/skills" activeClassName="">Skills</NavLink></li>
                    <li><NavLink className="navLink" exact to="/experience" activeClassName="">Experience</NavLink></li>
                  </ul>
                </div>
              </div>
                <Header />
              </div>
                    <div className="box-wrapper">
                        <Box />
                    </div>
              <div className="footer-wrap">
                <Footer />
              </div>
            </BrowserRouter>
      </div>
    );
  }

  export default Main;

ReactDOM.render(<Main />, document.getElementById('root'));
