import React from 'react';
import { NavLink } from 'react-router-dom';
import style from '../components/css/style.module.css';
import home from '../components/css/home.module.css';

function Home() {
    return (
      <div className={home.wrapper}>
        <h3 className={home.title}><span className={home.title_bg}>Y</span>oshimoto, <span className={home.title_bg}>M</span>ariko</h3>
        <h4 className={[home.subtitle, home.place].join(' ')}>Tokyo, Japan</h4>
        <h4 className={[home.subtitle, home.pos].join(' ')}>Web Developer / Frontend Developer</h4>
        <hr className={[style.box_hr, style.bg_grey].join(' ')} />
        <div className={home.text}>
          <p>
          <span className={[home.quote, home.quote_l].join(' ')}><i className="fas fa-quote-left"></i></span>A frontend developer based in Tokyo, Japan. For 4 years as a developer — I have mostly used WordPress(PHP) as my main prowess in the vast world of programming. Recently, I have been dabbling with JavaScript and its frameworks such as React and Node, starting with personal projects and sooner — hopefully in my profession as well.<span className={[home.quote, home.quote_r].join(' ')}><i className="fas fa-quote-right"></i></span>
          </p>
          <h2 className={home.show_link}>
            <NavLink className={[home.show_link, style.link].join(' ')} to="/skills" activeClassName="">See my portfolio</NavLink>
          </h2>
        </div>
      </div>
    );
  }

  export default Home;